export const parseTextAnnotations2BC = (txt,  cb) => {
    
    let lineText = { };
    let arrayText = txt?.[0]?.description.split('\n');
    arrayText.map((dd, ind2)=>{
        
            if(!lineText.dor && dd.split(" ").length===3){
                let hh = []
                dd.split(" ").map(aa=>{
                    if(!isNaN(aa*1)){
                        hh.push(aa*1)
                    }
                });
                lineText.dor = (new Date(hh[2],hh[1],hh[0])).getTime();
            }

            if(dd.toLowerCase().indexOf("omo")>0){
                lineText.tomo = arrayText?.[ind2+1]; 
            }

            if(dd.toLowerCase().indexOf("olio")>0){
                lineText.folio = arrayText?.[ind2+1]; 
            }

            if(!lineText.registration_officer && dd.indexOf("strador(a) del ")>0){
                let nInd = -1;
                if(arrayText?.[ind2+nInd].split(" ").length<=1){
                    nInd = -2;
                }
                lineText.registration_officer = clearTxt(arrayText?.[ind2+nInd]); 
            }
            
            if(dd.indexOf("eresada se expide la presen")>0){
                let patGran = dd.split("a presente a los")?.[1];
                let dateRecuested = parseLongTextDate(patGran);

                lineText.dop = dateRecuested;
            }

            if(!lineText.city_registration && dd.indexOf("ugar de nacimiento:")>0){
                let patGran = dd.split("ugar de nacimiento: ")?.[1]?.split(", ");
                lineText.city_registration = clearTxt(patGran?.[0]); 
                lineText.state_registration = clearTxt(patGran?.[1]);
            }
           
           if(dd.indexOf("uelos paternos:")>0){
               let patGran = dd.split("uelos paternos: ")?.[1]?.split(" y ");
                lineText.grandFather_FatherSide  = clearTxt(patGran?.[0]); 
                lineText.grandMother_FatherSide = clearTxt(patGran?.[1]);  
            }
            if(dd.indexOf("uelos maternos:")>0){
                let patGran = dd.split("uelos maternos: ")?.[1]?.split(" y ");
                lineText.grandFather_MotherSide = clearTxt(patGran?.[0]);
                lineText.grandMother_MotherSide = clearTxt(patGran?.[1]); 
            }
            if(dd.indexOf("ontado por:")>0){
                let patGran = dd.split("ontado por: ")?.[1]?.split(",");
                lineText.revised_by = clearTxt(patGran?.[0]); 
            }
            if(dd.indexOf("echo por:")>0){
                let patGran = dd.split("echo por: ")?.[1]?.split(",");
                lineText.prepared_by =clearTxt(patGran?.[0]); 
            }

          
        
    });
    
   return lineText;

}






