const clearTxt = (v) =>{
    v = v?.trim();
    v = v?.split(".").join("");
    v = v?.split(",").join("");
    return v;

}


const monthsName2Int = {
    "enero":0,
    "febrero":1,
    "marzo":2,
    "abril":3,
    "mayo":4,
    "junio":5,
    "julio":6,
    "agosto":7,
    "septiembre":8,
    "octubre":9,
    "noviembre":10,
    "diciembre":11
  }
  

const parseLongTextDate = (v) =>{
    v = v?.trim();
    v = v?.split("del").join("/");
    v = v?.split("días").join("");
    v = v?.split(" mes de ").join("");
    v = v?.split(" ").join("");
    v = v?.split(".").join("");
    let dtA=v?.split("/");
    if(dtA){
        let YYYY = dtA[2]*1;
        let MM = monthsName2Int[dtA[1]];
        let DD = dtA[0]*1;
        return (new Date(YYYY,MM,DD)).getTime();
    }
    return null;
}


const parseStringTextDate = (v) =>{
    v = v?.trim();
    v = v?.split("de").join("/");
    v = v?.split(" ").join("");
    let dtA=v?.split("/");
    if(dtA){
        let YYYY = dtA[2]*1;
        let MM = monthsName2Int[dtA[1]];
        let DD = dtA[0]*1;
        return (new Date(YYYY,MM,DD)).getTime();
    }
    return null;
}



export const getCurrentAddress  = (user) => {
    if(user["residences"]){
        const compareSort = (item) =>{
            let YY = item.toDate.year? item.toDate.year === "present" ? 99999 : item.toDate.year: "0";
            let MM = item.toDate.month || "0";
            return YY + "" + MM; 
        }
        let residences2S = convertObj2Array(user["residences"]);
        let address = sortAddress(residences2S,compareSort);
        return address[0];
    }
    return null;
}




