const parseSS = (v) =>{
	if(v){
		let f = v.substring(0,3) + "-"+ v.substring(3,5) + "-"+v.substring(5,9);
		return f;
	}
	return ""
}

export const parseAlien = (v) =>{
	if(v){
		let f = v.substring(0,3) + " "+ v.substring(3,6) + " "+v.substring(6,9);
		return f;
	}
	return ""
}

const parsePhoneNumber = (v) =>{
	if(v){
		let f = v.substring(0,3) + "     "+ v.substring(3,6) + " "+v.substring(6,10);
		return f;
	}
	return ""
}

export const sortAddress = (td, func) =>{
	let order = false;
	let sortedA = td && td.sort((a, b) => {
		let A =func(a)
		let B = func(b)
		if (A < B) {
			return order ? -1 : 1;
		}
		if (A > B) {
			return order ? 1 : -1;
		}
		return 0;
	});	
	return sortedA;
}






